/* ── PopDAM design tokens (light/dark + accent) ─────────────── */
:root {
  --pd-radius: 10px;
  --pd-radius-sm: 7px;
  --pd-radius-lg: 14px;
  --pd-shadow-sm: 0 1px 3px rgba(0,0,0,.06), 0 1px 2px rgba(0,0,0,.04);
