@tailwind base;
@tailwind components;
@tailwind utilities;

@layer base {
  :root {
    /* PopDAM Dark Theme — Single theme, no light mode */
    --background: 220 16% 12%;
    --foreground: 220 13% 91%;

    --card: 220 16% 15%;
    --card-foreground: 220 13% 91%;

    --popover: 220 16% 15%;
    --popover-foreground: 220 13% 91%;

    --primary: 38 92% 55%;
    --primary-foreground: 220 16% 10%;

    --secondary: 220 14% 20%;
    --secondary-foreground: 220 13% 85%;

    --muted: 220 14% 18%;
    --muted-foreground: 220 10% 55%;

    --accent: 220 14% 22%;
    --accent-foreground: 220 13% 91%;

    --destructive: 0 72% 51%;
    --destructive-foreground: 0 0% 98%;

    --border: 220 14% 22%;
    --input: 220 14% 22%;
    --ring: 38 92% 55%;

    --radius: 0.5rem;

    /* Semantic surface tokens */
    --surface-elevated: 220 16% 17%;
    --surface-overlay: 220 16% 10%;

    /* Tag tokens */
    --tag-bg: 220 14% 24%;
    --tag-foreground: 220 13% 80%;

    /* Status tokens */
    --success: 142 71% 45%;
    --success-foreground: 0 0% 98%;
    --warning: 38 92% 55%;
    --warning-foreground: 220 16% 10%;
    --info: 217 91% 60%;
    --info-foreground: 0 0% 98%;

    /* Sidebar */
    --sidebar-background: 220 16% 10%;
    --sidebar-foreground: 220 13% 80%;
    --sidebar-primary: 38 92% 55%;
    --sidebar-primary-foreground: 220 16% 10%;
    --sidebar-accent: 220 14% 18%;
    --sidebar-accent-foreground: 220 13% 91%;
    --sidebar-border: 220 14% 18%;
    --sidebar-ring: 38 92% 55%;
  }
}

@layer base {
  * {
    @apply border-border;
  }

  body {
    @apply bg-background text-foreground font-sans antialiased;
  }
}

@keyframes shimmer {
  0% { transform: translateX(-50%); }
  100% { transform: translateX(0); }
}
